const sharp = require\('sharp'\);
const fs = require\('fs'\);
const path = require\('path'\);

async function optimizeAll\(\) {
  const dirs = ['public/images/rooms', 'public/images/hotel', 'public/images/services'];
  let totalBefore = 0, totalAfter = 0;

  for \(const dir of dirs\) {
    const files = fs.readdirSync\(dir\).filter\(f => f.endsWith\('.jpg'\)\);
    for \(const file of files\) {
      const src = path.join\(dir, file\);
      const dst = path.join\(dir, file.replace\('.jpg', '.webp'\)\);
      const beforeSize = fs.statSync\(src\).size;
      totalBefore += beforeSize;

      await sharp\(src\)
        .resize\(1200, null, { withoutEnlargement: true }\)
        .webp\({ quality: 78 }\)
        .toFile\(dst\);

      const afterSize = fs.statSync\(dst\).size;
      totalAfter += afterSize;
      console.log\(file, '->', \(beforeSize/1024\).toFixed\(0\)+'KB', '->', \(afterSize/1024\).toFixed\(0\)+'KB'\);
    }
  }
  console.log\('\\\\nTotal: ' + \(totalBefore/1024\).toFixed\(0\) + 'KB -> ' + \(totalAfter/1024\).toFixed\(0\) + 'KB'\);
  console.log\('Ahorro: ' + \(\(1 - totalAfter/totalBefore\)*100\).toFixed\(0\) + '%'\);
}
optimizeAll\(\).catch\(console.error\);
")
